CalculateField test_POI Typr assign_value(!type!) PYTHON_9.3 "def assign_value(field_value):
 # 处理空值
 if field_value is None:
 return None
 # 确保转换为Unicode字符串（在Python 2中）
 try:
 # 如果已经是unicode，则直接使用
 if isinstance(field_value, unicode):
 field_str = field_value
 else:
 # 假设原始编码是utf-8，如果不是，可以尝试gbk等
 field_str = unicode(field_value, 'utf-8')
 except:
 # 如果转换失败，尝试用gbk解码
 try:
 field_str = unicode(field_value, 'gbk')
 except:
 # 如果还是失败，则使用原值并转换为unicode（忽略错误）
 field_str = unicode(field_value, errors='ignore')
 # 检查是否包含“餐饮服务”
 if u"餐饮服务" in field_str:
 return 99
 else:
 # 注意：如果字段是文本类型，返回99可能会被自动转换为字符串，但这里我们希望赋值为数值99
 # 因此，需要确保字段是数值类型（整型或浮点型）才能赋值99。如果是文本字段，则返回字符串"99"
 # 根据你的需求，这里返回99（数值）还是"99"（字符串）取决于字段类型
 return field_value"

