CalculateField test_POI Typr assign_value(!type!) PYTHON "def assign_value(field_value):
 # 处理空值
 if field_value is None:
 return None

 # 确保转换为Unicode字符串（在Python 2中）
 try:
 # 如果已经是unicode，则直接使用
 if isinstance(field_value, unicode):
 field_str = field_value
 else:
 # 假设原始编码是utf-8，如果不是，可以尝试gbk等
 field_str = unicode(field_value, 'utf-8')
 except:
 # 如果转换失败，尝试用gbk解码
 try:
 field_str = unicode(field_value, 'gbk')
 except:
 # 如果还是失败，则使用原值并转换为unicode（忽略错误）
 field_str = unicode(field_value, errors='ignore')

 # 按优先级检查各个关键词
 # 注意：这里使用if-elif结构，一旦匹配就不再检查后面的条件
 if u"餐饮服务" in field_str:
 return u"餐饮"
 elif u"购物服务" in field_str:
 return u"购物"
 elif u"生活服务" in field_str:
 return u"生活"
 elif u"体育休闲服务" in field_str:
 return u"体育休闲"
 elif u"医疗保健服务" in field_str:
 return u"医疗保健"
 elif u"政府机构" in field_str:
 return u"政府"
 else:
 # 都不匹配，返回原值
 return field_value"
